import { Schema } from "effect"

const HexPrefixedString = Schema.pattern(/^0x[0-9a-fA-F]+$/)

// Branded IDs
export const TxHash = Schema.String.pipe(
  HexPrefixedString,
  Schema.brand("@Falcon/TxHash"),
)
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(
  HexPrefixedString,
  Schema.brand("@Falcon/ContractAddress"),
)
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

import { Context, Effect, Layer } from "effect"
import { WasmLoadError } from "./errors"

export interface WasmModule {
  readonly keygen: (seed: Uint8Array) => { sk: Uint8Array; vk: Uint8Array }
  readonly sign: (
    skBytes: Uint8Array,
    message: Uint8Array,
    salt: Uint8Array,
  ) => {
    signature: Uint8Array
    salt: Uint8Array
  }
  readonly verify: (
    vkBytes: Uint8Array,
    message: Uint8Array,
    signature: Uint8Array,
  ) => boolean
  readonly create_verification_hint: (
    s1: Int32Array,
    pkNtt: Int32Array,
  ) => Uint16Array
  readonly pack_public_key_wasm: (pkNtt: Uint16Array) => string[]
  readonly public_key_length: () => number
  readonly salt_length: () => number
}

export class WasmRuntime extends Context.Tag("WasmRuntime")<
  WasmRuntime,
  WasmModule
>() {}

/**
 * Runtime type guard вҖ” validates that a dynamically-imported module exposes
 * every required method of the WasmModule interface.
 *
 * This eliminates unsafe `as unknown as WasmModule` casts by verifying the
 * module shape at runtime before TypeScript accepts it as WasmModule. Any
 * mismatch between the compiled Rust bindings and the TypeScript interface is
 * caught immediately at load time rather than silently at call time.
 */
export function isValidWasmModule(mod: unknown): mod is WasmModule {
  if (typeof mod !== "object" || mod === null) return false
  const o = mod as Record<string, unknown>
  return (
    typeof o["keygen"] === "function" &&
    typeof o["sign"] === "function" &&
    typeof o["verify"] === "function" &&
    typeof o["create_verification_hint"] === "function" &&
    typeof o["pack_public_key_wasm"] === "function" &&
    typeof o["public_key_length"] === "function" &&
    typeof o["salt_length"] === "function"
  )
}

/**
 * Live Layer вҖ” loads the WASM module via dynamic import, validates the
 * exported bindings at runtime using `isValidWasmModule`, and provides the
 * result as the WasmRuntime service.
 *
 * Caching: `Layer.effect` is memoized by the Effect layer system. When
 * `WasmRuntimeLive` is provided to the application, the loading effect runs
 * exactly once per layer scope. No mutable global `cachedModule` variable is
 * required вҖ” Effect's own Layer memoization provides the singleton guarantee.
 */
export const WasmRuntimeLive = Layer.effect(
  WasmRuntime,
  Effect.gen(function* () {
    const mod = yield* Effect.tryPromise({
      // Return type is Promise<unknown> so TypeScript sees `mod` as `unknown`,
      // forcing us through the runtime validator before the type is narrowed.
      try: async (): Promise<unknown> => {
        // Dynamic import resolved at runtime in the browser; this file is not
        // a TypeScript module вҖ” suppress compile-time module-not-found error.
        // @ts-expect-error -- WASM served from /public/wasm/ at runtime
        const m = await import("/wasm/falcon_rs.js")
        await m.default()
        return m
      },
      catch: (error) =>
        new WasmLoadError({ message: `Failed to load WASM module: ${String(error)}` }),
    })

    if (!isValidWasmModule(mod)) {
      return yield* Effect.fail(
        new WasmLoadError({
          message:
            "WASM module is missing required methods. " +
            "Expected: keygen, sign, verify, create_verification_hint, " +
            "pack_public_key_wasm, public_key_length, salt_length.",
        }),
      )
    }

    return mod
  }),
)

