const PACKED_BYTE_LEN = (N * BITS_PER_COEFF) / 8 // 896
/** Byte length including the 1-byte Falcon header */
const PACKED_WITH_HEADER_LEN = PACKED_BYTE_LEN + 1 // 897
/** Bitmask for extracting a single 14-bit coefficient */
const COEFF_MASK = (1 << BITS_PER_COEFF) - 1 // 0x3FFF

/**
 * Deserialize a Falcon-512 verifying key into 512 NTT-domain coefficients.
 *
 * Accepts either:
 * - 896 bytes (raw packed coefficients)
 * - 897 bytes (1-byte Falcon header + 896 coefficient bytes)
 *
 * Each coefficient is validated to be in [0, Q) where Q = 12289.
 *
 * @throws Error if length is invalid or any coefficient >= Q
 */
export function deserializePublicKeyNtt(vkBytes: Uint8Array): Int32Array {
  let data: Uint8Array
  if (vkBytes.length === PACKED_WITH_HEADER_LEN) {
    // Strip 1-byte header (standard Falcon format)
    data = vkBytes.subarray(1)
  } else if (vkBytes.length === PACKED_BYTE_LEN) {
    data = vkBytes
  } else {
    throw new Error(
      `Invalid verifying key length: ${vkBytes.length} bytes (expected ${PACKED_BYTE_LEN} or ${PACKED_WITH_HEADER_LEN})`,
    )
  }

  const coeffs = new Int32Array(N)
  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 0

  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS_PER_COEFF) {
      bitBuffer |= data[byteIndex++]! << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & COEFF_MASK
    bitBuffer >>>= BITS_PER_COEFF
    bitsInBuffer -= BITS_PER_COEFF

    if (coeff >= Q) {
      throw new Error(
        `Invalid coefficient ${coeff} at index ${i} (must be < ${Q})`,
      )
    }
    coeffs[i] = coeff
  }

  return coeffs
}

/**
 * Serialize 512 NTT-domain coefficients into 896 packed bytes.
 *
 * Each coefficient is stored as 14 bits, packed LSB-first.
 * This is the inverse of `deserializePublicKeyNtt` (without header byte).
 *
 * Primarily used for testing roundtrips.
 *
 * @throws Error if input is not 512 coefficients or any coefficient is out of range
 */
export function serializePublicKeyNtt(coeffs: Int32Array): Uint8Array {
  if (coeffs.length !== N) {
    throw new Error(
      `Input must have exactly 512 coefficients, got ${coeffs.length}`,
    )
  }

  const bytes = new Uint8Array(PACKED_BYTE_LEN)
  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 0

  for (let i = 0; i < N; i++) {
    const coeff = coeffs[i]!
    if (coeff < 0 || coeff >= Q) {
      throw new Error(
        `Invalid coefficient ${coeff} at index ${i} (must be in [0, ${Q}))`,
      )
    }
    bitBuffer |= coeff << bitsInBuffer
    bitsInBuffer += BITS_PER_COEFF

    while (bitsInBuffer >= 8) {
      bytes[byteIndex++] = bitBuffer & 0xFF
      bitBuffer >>>= 8
      bitsInBuffer -= 8
    }
  }

  // Flush remaining bits (should be 0 since 512*14 = 7168 = 896*8, perfectly aligned)
  if (bitsInBuffer > 0) {
    bytes[byteIndex] = bitBuffer & 0xFF
  }

  return bytes
}
```

